            return response.json();
        })
        .then(data => {
            updateWidget(data); // Function to update your widget
        })
        .catch(error => {
            if (retries > 0) {
                console.warn(`Retrying... Attempts left: ${retries}`);
                setTimeout(() => fetchSyncStatus(retries - 1, delay * 2), delay); // Exponential backoff
            } else {
                console.error('Failed to fetch sync status after retries:', error);
                // Optionally, update the widget to show an error state
            }
        });
}

// Call the function to start fetching
fetchSyncStatus();
```

This example uses exponential backoff by doubling the delay with each retry. Adjust the number of retries and the initial delay based on your needs. This should help provide a smoother experience for your demo.
